import { mkdir, readFile, writeFile } from "node:fs/promises";

const packageRoot = new URL("../", import.meta.url);
const schemaUrl = new URL("schema/sal-object.schema.json", packageRoot);
const outputUrl = new URL("src/generated/sal-object-schema-data.ts", packageRoot);

const schemaText = await readFile(schemaUrl, "utf8");
JSON.parse(schemaText);

const source = [
  "// Generated by scripts/generate-schema-data.mjs. Do not edit directly.",
  `export const salObjectSchemaText: string = ${JSON.stringify(schemaText)};`,
].join("\n\n") + "\n";

await mkdir(new URL("src/generated/", packageRoot), { recursive: true });
await writeFile(outputUrl, source, "utf8");
